import{_ as t,H as a,f as i,i as l}from"./chunks/framework.Cvt1eIE0.js";const h=JSON.parse('{"title":"Context","description":"","frontmatter":{"title":"Context","layout":"default"},"headers":[],"relativePath":"context.md","filePath":"context.md"}'),r={name:"context.md"};function o(s,e,n,c,d,p){return a(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h1><h2 id="runtime-strategy" tabindex="-1">Runtime strategy <a class="header-anchor" href="#runtime-strategy" aria-label="Permalink to &quot;Runtime strategy&quot;">​</a></h2><p>The current tracer runtime is optimized for stability-first integration in complex editor environments.</p><h3 id="default-principles" tabindex="-1">Default principles <a class="header-anchor" href="#default-principles" aria-label="Permalink to &quot;Default principles&quot;">​</a></h3><ol><li>No automatic property wrapping in <code>observe(...)</code>.</li><li>Property watchers are opt-in and explicit.</li><li>Hybrid object strategy:</li></ol><ul><li>no proxy by default for property object observation;</li><li>proxy only for explicit and safe plain-object cases.</li></ul><ol start="4"><li>Non-full profiles suppress noisy paths and reduce overhead.</li></ol><h2 id="profiles" tabindex="-1">Profiles <a class="header-anchor" href="#profiles" aria-label="Permalink to &quot;Profiles&quot;">​</a></h2><ul><li><code>minimal</code>: production-safe baseline with lowest tracing overhead.</li><li><code>balanced</code>: default profile, same behavior as minimal.</li><li><code>full</code>: diagnostics mode (calls + properties + context).</li></ul><h2 id="event-streams" tabindex="-1">Event streams <a class="header-anchor" href="#event-streams" aria-label="Permalink to &quot;Event streams&quot;">​</a></h2><ul><li>Global stream: <ul><li>call traces</li><li>explicitly configured property watchers (manual)</li></ul></li><li>Slice-scoped stream: <ul><li>trace subset active only between slice start/end conditions</li><li>usage collection for classes/methods/properties only inside active window</li></ul></li></ul><h2 id="why-this-split-matters" tabindex="-1">Why this split matters <a class="header-anchor" href="#why-this-split-matters" aria-label="Permalink to &quot;Why this split matters&quot;">​</a></h2><ul><li>Global stream keeps explicit watchers reliable.</li><li>Slice-scoped stream allows targeted diagnostics and run-level comparisons.</li><li>Combined model reduces regressions while keeping useful observability.</li></ul><h2 id="current-behavior-contract" tabindex="-1">Current behavior contract <a class="header-anchor" href="#current-behavior-contract" aria-label="Permalink to &quot;Current behavior contract&quot;">​</a></h2><ol><li><code>observe(...)</code> and <code>observePrototype(...)</code> do not auto-wrap arbitrary object properties.</li><li>Manual property watchers stay active globally, regardless of active slices.</li><li>Slice reports (<code>ReportSliceDiff</code>, <code>ReportSliceUsage</code>) aggregate only slice-contained events.</li><li>Slice lifecycle is controlled by start/end predicates and can be exported/imported across teams.</li></ol>',15)])])}const m=t(r,[["render",o]]);export{h as __pageData,m as default};
